def validate(args, outputs):
    ops, arg_lists = args
    if not isinstance(outputs, list) or len(outputs) != len(ops):
        return False
    if ops[0] != 'Solution':
        return False
    m, n = arg_lists[0]
    total = m * n
    flipped = set()
    for i in range(1, len(ops)):
        op, out = ops[i], outputs[i]
        if op == 'flip':
            if not (isinstance(out, list) and len(out) == 2):
                return False
            r, c = out
            if not isinstance(r, int) or isinstance(r, bool):
                return False
            if not isinstance(c, int) or isinstance(c, bool):
                return False
            if r < 0 or r >= m or c < 0 or c >= n:
                return False
            key = r * n + c
            if key in flipped or len(flipped) >= total:
                return False
            flipped.add(key)
        elif op == 'reset':
            if out is not None:
                return False
            flipped = set()
    return True

