function validate(args, outputs) {
  const [ops, argLists] = args;
  if (!Array.isArray(outputs) || outputs.length !== ops.length) return false;
  if (ops[0] !== 'Solution') return false;
  const [m, n] = argLists[0];
  const total = m * n;
  let flipped = new Set();
  for (let i = 1; i < ops.length; i++) {
    const op = ops[i], out = outputs[i];
    if (op === 'flip') {
      if (!Array.isArray(out) || out.length !== 2) return false;
      const [r, c] = out;
      if (typeof r !== 'number' || !Number.isInteger(r)) return false;
      if (typeof c !== 'number' || !Number.isInteger(c)) return false;
      if (r < 0 || r >= m || c < 0 || c >= n) return false;
      const key = r * n + c;
      if (flipped.has(key) || flipped.size >= total) return false;
      flipped.add(key);
    } else if (op === 'reset') {
      if (out !== null) return false;
      flipped = new Set();
    }
  }
  return true;
}

