import random


class Solution:
    def __init__(self, m, n):
        self.m = m
        self.n = n
        self.flipped = set()

    def flip(self):
        while True:
            r = random.randrange(self.m)
            c = random.randrange(self.n)
            if (r, c) not in self.flipped:
                self.flipped.add((r, c))
                return [r, c]

    def reset(self):
        self.flipped = set()

