import random


class Solution:
    def __init__(self, m, n):
        self.m = m
        self.n = n
        self.total = m * n
        self.remaining = self.total
        self.map = {}

    def flip(self):
        r = random.randrange(self.remaining)
        x = self.map.get(r, r)
        last = self.remaining - 1
        self.map[r] = self.map.get(last, last)
        self.remaining -= 1
        return [x // self.n, x % self.n]

    def reset(self):
        self.remaining = self.total
        self.map = {}

