var Solution = function(m, n) {
    this.m = m;
    this.n = n;
    this.total = m * n;
    this.remaining = this.total;
    this.map = new Map();
};

Solution.prototype.flip = function() {
    const r = Math.floor(Math.random() * this.remaining);
    const x = this.map.has(r) ? this.map.get(r) : r;
    const last = this.remaining - 1;
    this.map.set(r, this.map.has(last) ? this.map.get(last) : last);
    this.remaining--;
    return [Math.floor(x / this.n), x % this.n];
};

Solution.prototype.reset = function() {
    this.remaining = this.total;
    this.map = new Map();
};
